public class Person {
  private String name;
  private int age;

  // Default konstruktor
  public Person() {
    name = "Bilinməyən";
    age = 0;
  }

  public void display() {
    String message = "Ad: " + name + ", Yaş: " + age;
    System.out.println(message);
  }

  public static void main(String[] args) {
    Person person = new Person();
    person.display();
  }
}
// Çıxış: Ad: Bilinməyən, Yaş: 0

public class Person {
  private String name;
  private int age;

  // Parametrli konstruktor
  public Person(String name, int age) {
    this.name = name;
    if (age >= 0) {
      this.age = age;
    } else {
      this.age = 0;
      System.out.println("Yaş mənfi ola bilməz!");
    }
  }

  public void display() {
    String message = "Ad: " + name + ", Yaş: " + age;
    System.out.println(message);
  }

  public static void main(String[] args) {
    Person person = new Person("Ali", 25);
    person.display();
    Person invalidPerson = new Person("Vəli", -5);
    invalidPerson.display();
  }
}
// Çıxış:
// Ad: Ali, Yaş: 25
// Yaş mənfi ola bilməz!
// Ad: Vəli, Yaş: 0

public class Person {
  private String name;
  private int age;

  // Default konstruktor
  public Person() {
    this("Bilinməyən", 0);
  }

  // Parametrli konstruktor
  public Person(String name, int age) {
    this.name = name;
    this.age = age >= 0 ? age : 0;
    if (age < 0) {
      System.out.println("Yaş mənfi ola bilməz!");
    }
  }

  public void display() {
    String message = "Ad: " + name + ", Yaş: " + age;
    System.out.println(message);
  }

  public static void main(String[] args) {
    Person person1 = new Person();
    person1.display();
    Person person2 = new Person("Aygün", 30);
    person2.display();
  }
}
// Çıxış:
// Ad: Bilinməyən, Yaş: 0
// Ad: Aygün, Yaş: 30

